@st.cache_data(ttl=120, show_spinner=False)
def get_modo_claro(profesor_id):
    try:
        res = supabase.table("preferencias_usuario").select("modo_claro").eq("profesor_id", profesor_id).execute()
        if res.data:
            return res.data[0].get("modo_claro", False)
        return False
    except: return False

def set_modo_claro(profesor_id, valor):
    try:
        res = supabase.table("preferencias_usuario").select("id").eq("profesor_id", profesor_id).execute()
        if res.data:
            supabase.table("preferencias_usuario").update({"modo_claro": valor}).eq("profesor_id", profesor_id).execute()
        else:
            supabase.table("preferencias_usuario").insert({"profesor_id": profesor_id, "modo_claro": valor}).execute()
    except: pass

def extraer_nombre_limpio(nombre_curso):
    """Devuelve el nombre del curso sin los días ni el horario entre paréntesis y pipe."""
    try:
        if '(' in nombre_curso:
            return nombre_curso.split('(')[0].strip()
        if '|' in nombre_curso:
            return nombre_curso.split('|')[0].strip()
    except: pass
    return nombre_curso.strip()

def get_clases_hoy(profesor_id, mapa_cursos, mapa_cursos_data):
    """Devuelve lista de cursos con clase hoy.
    Busca los dias en el nombre completo guardado en BD (nombre_curso_materia),
    que siempre tiene el formato: Nombre (Dia1, Dia2) | HH:MM -> HH:MM"""
    hoy = datetime.date.today()
    dia_hoy = hoy.weekday()
    clases = []
    for nombre_curso, inscripcion_id in mapa_cursos.items():
        curso_data = mapa_cursos_data.get(nombre_curso, {})
        # Buscar dias primero en el nombre_curso_materia de BD, luego en la clave del mapa
        nombre_en_bd = curso_data.get('nombre_curso_materia', nombre_curso)
        dias = extraer_dias_curso(nombre_en_bd)
        if not dias:
            dias = extraer_dias_curso(nombre_curso)
        if not dias or dia_hoy not in dias:
            continue
        hi = str(curso_data.get('hora_inicio', '') or '')[:5]
        hf = str(curso_data.get('hora_fin', '') or '')[:5]
        horario = format_horario(hi, hf) if hi else "-"
        try:
            res = supabase.table("bitacora").select("id").eq("inscripcion_id", inscripcion_id).eq("fecha", str(hoy)).execute()
            ya_registrada = len(res.data) > 0
        except:
            ya_registrada = False
        clases.append({
            'nombre': nombre_curso,
            'nombre_limpio': extraer_nombre_limpio(nombre_en_bd),
            'horario': horario,
            'ya_registrada': ya_registrada,
        })
    return clases

def get_clases_no_registradas(profesor_id, mapa_cursos, mapa_cursos_data, cal_sede=None):
    """Devuelve lista de fechas pasadas con clase programada pero sin registro en bitácora.
    Requiere que el calendario de la sede tenga fecha_inicio configurada.
    Si no está configurada, devuelve None para mostrar aviso al profesor."""
    hoy = datetime.date.today()

    # Verificar que haya fecha de inicio configurada
    if not cal_sede or not cal_sede.get('fecha_inicio'):
        return None  # Señal de que no está configurado el calendario

    try:
        fecha_inicio_busq = datetime.date.fromisoformat(cal_sede['fecha_inicio'])
    except:
        return None

    # No buscar fechas futuras ni de hoy
    if fecha_inicio_busq >= hoy:
        return []

    pendientes = []
    for nombre_curso, inscripcion_id in mapa_cursos.items():
        curso_data = mapa_cursos_data.get(nombre_curso, {})
        nombre_en_bd = curso_data.get('nombre_curso_materia', nombre_curso)
        dias_clase = extraer_dias_curso(nombre_en_bd)
        if not dias_clase:
            dias_clase = extraer_dias_curso(nombre_curso)
        if not dias_clase:
            continue
        hi = str(curso_data.get('hora_inicio', '') or '')[:5]
        hf = str(curso_data.get('hora_fin', '') or '')[:5]
        horario = format_horario(hi, hf) if hi else "-"
        # Traer todos los registros de bitácora del curso de una sola vez
        try:
            res_bit = supabase.table("bitacora").select("fecha, contenido_clase").eq(
                "inscripcion_id", inscripcion_id
            ).gte("fecha", str(fecha_inicio_busq)).lte("fecha", str(hoy)).execute()
            fechas_registradas = set()
            for r in (res_bit.data or []):
                fechas_registradas.add(r['fecha'])
        except:
            fechas_registradas = set()
        # Iterar por cada fecha desde inicio hasta ayer (hoy no cuenta aún)
        cursor = fecha_inicio_busq
        while cursor < hoy:
            if cursor.weekday() in dias_clase:
                fecha_str = str(cursor)
                if fecha_str not in fechas_registradas:
                    pendientes.append({
                        'curso': nombre_curso,
                        'nombre_limpio': extraer_nombre_limpio(nombre_en_bd),
                        'inscripcion_id': inscripcion_id,
                        'fecha': cursor,
                        'fecha_str': fecha_str,
                        'horario': horario,
                    })
            cursor += datetime.timedelta(days=1)
    # Ordenar por fecha descendente (más reciente primero)
    pendientes.sort(key=lambda x: x['fecha'], reverse=True)
    return pendientes

